/**
 * Generate Atlas Cloud firewall config.
 *
 * Data sources:
 * - https://www.atlascloud.ai/docs/api-keys
 * - https://www.atlascloud.ai/docs/en/models/get-start
 *
 * Atlas Cloud uses Bearer token authentication via Authorization header.
 * The API key format is not publicly documented.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.atlascloud.ai/docs/api-keys";
const PLACEHOLDER_VALUE =
  "c0ffee5afe10ca1c0ffee5afe10ca1c0ffee5afe10ca1c0ffee5afe10ca1c0ff";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Atlas Cloud API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:atlascloud",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const atlascloudFirewall = {",
    '  name: "atlascloud",',
    '  description: "Atlas Cloud API",',
    "  placeholders: {",
    `    ATLASCLOUD_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.atlascloud.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.ATLASCLOUD_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Atlas Cloud firewall config...");
  const ts = generateTypeScript();
  writeOutput("atlascloud", ts, import.meta.dirname);
}
